DROP VIEW "milestone";--> statement-breakpoint
CREATE VIEW "milestone" AS (select "aggregate_id" as "id", (array_agg("payload"->>'project_id' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'project_id')))[1] as "project_id", (array_agg("payload"->>'title' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'title')))[1] as "title", ((array_agg("payload"->>'cost' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'cost')))[1])::numeric as "cost", (array_agg("payload"->>'currency' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'currency')))[1] as "currency", (array_agg("payload"->>'state' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'state')))[1] as "state", ((array_agg("payload"->>'due_at' ORDER BY "version" DESC) FILTER (WHERE jsonb_exists("payload", 'due_at')))[1])::timestamp with time zone as "due_at", (array_agg("recorded_at" ORDER BY "version" ASC))[1] as "created_at" from "event" where "event"."aggregate_type" = 'milestone' group by "event"."aggregate_id");